```c
#include <stdio.h>

int gcd(int a, int b) {
    if (b == 0) {
        return a;
    } else {
        return gcd(b, a % b);
    }
}

void solve(int x, int y, char a, char b) {
    char ans[1000] = "";
    int index = 0;
    while (x != 1 || y != 1) {
        if (x < y) {
            int temp = x;
            x = y;
            y = temp;
            char c = a;
            a = b;
            b = c;
        }
        int count = (x - 1) / y;
        index += sprintf(ans + index, "%d%c", count, a);
        x = x - count * y;
    }
    printf("%s\n", ans);
}

int main() {
    int x, y;
    scanf("%d %d", &x, &y);
    if (gcd(x, y) > 1) {
        printf("Impossible\n");
    } else {
        solve(x, y, 'A', 'B');
    }
    return 0;
}
```

